import{s}from"./request-DBycRpqs.js";const p={getRecommendedPosts(t,e){return s.get("/post/recommended",{params:{pageNum:t,pageSize:e}})},getFollowingPosts(t,e){return s.get("/post/following",{params:{pageNum:t,pageSize:e}})},getHotPosts(t,e){return s.get("/post/hot",{params:{pageNum:t,pageSize:e}})},getUserPosts(t,e,o){return s.get(`/post/user/${t}`,{params:{pageNum:e,pageSize:o}})},getPostDetail(t){return s.get(`/post/${t}`)},getComments(t){return s.get(`/post/${t}/comments`)},addComment(t,e,o=0){return s.post("/post/comment",{postId:t,content:e,parentId:o})},likePost(t){return s.post(`/post/${t}/like`)},unlikePost(t){return s.delete(`/post/${t}/like`)},publishPost(t,e,o){return s.post("/post",{content:t,imageUrls:e,visibility:o})}};export{p};
